  "$SCRIPT_DIR/../../../../import/dma_axi/src/dma_axi64/prgen_delay.v" \
  "$SCRIPT_DIR/tb_prgen_delay.v" \
  -I "$SCRIPT_DIR/../../../../import/dma_axi/src/dma_axi64" \
  -I "$SCRIPT_DIR/../../../../import/dma_axi/src/dma_axi64" \
  --allow-use-before-declare \
  --lint-only \
  --timescale "1ns/1ps"

echo "PASS: prgen_delay testbench compiled successfully"